import {
  Pagination as PaginationPrimitive,
  usePagination,
  usePaginationContext,
} from '@ark-ui/react/pagination';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { ChevronLeftIcon, ChevronRightIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Pagination.module.css';

const PaginationRoot = forwardRef<
  ComponentRef<typeof PaginationPrimitive.Root>,
  ComponentProps<typeof PaginationPrimitive.Root>
>(function PaginationRoot({ 'aria-label': ariaLabel = 'Pagination', className, ...props }, ref) {
  return (
    <PaginationPrimitive.Root
      ref={ref}
      data-slot="pagination-root"
      aria-label={ariaLabel}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const PaginationRootProvider = forwardRef<
  ComponentRef<typeof PaginationPrimitive.RootProvider>,
  ComponentProps<typeof PaginationPrimitive.RootProvider>
>(function PaginationRootProvider(
  { 'aria-label': ariaLabel = 'Pagination', className, ...props },
  ref,
) {
  return (
    <PaginationPrimitive.RootProvider
      ref={ref}
      data-slot="pagination-root-provider"
      aria-label={ariaLabel}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const PaginationItem = forwardRef<
  ComponentRef<typeof PaginationPrimitive.Item>,
  ComponentProps<typeof PaginationPrimitive.Item>
>(function PaginationItem({ className, ...props }, ref) {
  return (
    <PaginationPrimitive.Item
      ref={ref}
      data-slot="pagination-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const PaginationEllipsis = forwardRef<
  ComponentRef<typeof PaginationPrimitive.Ellipsis>,
  ComponentProps<typeof PaginationPrimitive.Ellipsis>
>(function PaginationEllipsis({ className, children, ...props }, ref) {
  return (
    <PaginationPrimitive.Ellipsis
      ref={ref}
      data-slot="pagination-ellipsis"
      className={clsx(styles.ellipsis, normalizeClassName(className))}
      {...props}
    >
      {children ?? '...'}
    </PaginationPrimitive.Ellipsis>
  );
});

function EdgeIcon({ side }: { side: 'left' | 'right' }) {
  const Icon = side === 'left' ? ChevronLeftIcon : ChevronRightIcon;

  return (
    <span className={styles.edgeIcon} aria-hidden>
      <Icon />
      <Icon />
    </span>
  );
}

const PaginationPrevTrigger = forwardRef<
  ComponentRef<typeof PaginationPrimitive.PrevTrigger>,
  ComponentProps<typeof PaginationPrimitive.PrevTrigger>
>(function PaginationPrevTrigger({ className, children, ...props }, ref) {
  return (
    <PaginationPrimitive.PrevTrigger
      ref={ref}
      data-slot="pagination-prev-trigger"
      className={clsx(
        styles.trigger,
        children == null && styles.iconTrigger,
        normalizeClassName(className),
      )}
      {...props}
    >
      {children ?? <ChevronLeftIcon />}
    </PaginationPrimitive.PrevTrigger>
  );
});

const PaginationNextTrigger = forwardRef<
  ComponentRef<typeof PaginationPrimitive.NextTrigger>,
  ComponentProps<typeof PaginationPrimitive.NextTrigger>
>(function PaginationNextTrigger({ className, children, ...props }, ref) {
  return (
    <PaginationPrimitive.NextTrigger
      ref={ref}
      data-slot="pagination-next-trigger"
      className={clsx(
        styles.trigger,
        children == null && styles.iconTrigger,
        normalizeClassName(className),
      )}
      {...props}
    >
      {children ?? <ChevronRightIcon />}
    </PaginationPrimitive.NextTrigger>
  );
});

const PaginationFirstTrigger = forwardRef<
  ComponentRef<typeof PaginationPrimitive.FirstTrigger>,
  ComponentProps<typeof PaginationPrimitive.FirstTrigger>
>(function PaginationFirstTrigger({ className, children, ...props }, ref) {
  return (
    <PaginationPrimitive.FirstTrigger
      ref={ref}
      data-slot="pagination-first-trigger"
      className={clsx(
        styles.trigger,
        children == null && styles.iconTrigger,
        normalizeClassName(className),
      )}
      {...props}
    >
      {children ?? <EdgeIcon side="left" />}
    </PaginationPrimitive.FirstTrigger>
  );
});

const PaginationLastTrigger = forwardRef<
  ComponentRef<typeof PaginationPrimitive.LastTrigger>,
  ComponentProps<typeof PaginationPrimitive.LastTrigger>
>(function PaginationLastTrigger({ className, children, ...props }, ref) {
  return (
    <PaginationPrimitive.LastTrigger
      ref={ref}
      data-slot="pagination-last-trigger"
      className={clsx(
        styles.trigger,
        children == null && styles.iconTrigger,
        normalizeClassName(className),
      )}
      {...props}
    >
      {children ?? <EdgeIcon side="right" />}
    </PaginationPrimitive.LastTrigger>
  );
});

const PaginationContext = PaginationPrimitive.Context;

function PaginationItems() {
  return (
    <PaginationContext>
      {(pagination) =>
        pagination.pages.map((page, index) =>
          page.type === 'page' ? (
            <PaginationItem key={index} {...page}>
              {page.value}
            </PaginationItem>
          ) : (
            <PaginationEllipsis key={index} index={index} />
          ),
        )
      }
    </PaginationContext>
  );
}

const Pagination = Object.assign(PaginationRoot, {
  Root: PaginationRoot,
  RootProvider: PaginationRootProvider,
  Item: PaginationItem,
  Ellipsis: PaginationEllipsis,
  PrevTrigger: PaginationPrevTrigger,
  NextTrigger: PaginationNextTrigger,
  FirstTrigger: PaginationFirstTrigger,
  LastTrigger: PaginationLastTrigger,
  Context: PaginationContext,
  Items: PaginationItems,
  usePagination,
  usePaginationContext,
});

export { Pagination };

@layer moduix.components {
  .root {
    display: inline-flex;
    align-items: center;
    gap: var(--moduix-pagination-gap, var(--moduix-spacing-1));
    color: var(--moduix-pagination-color, var(--moduix-color-foreground));
  }

  .item,
  .trigger,
  .ellipsis {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: var(--moduix-pagination-item-size, var(--moduix-size-md));
    height: var(--moduix-pagination-item-size, var(--moduix-size-md));
    border-radius: var(--moduix-pagination-item-radius, var(--moduix-radius-md));
    font-size: var(--moduix-pagination-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-pagination-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-pagination-line-height, var(--moduix-line-height-text-sm));
    font-variant-numeric: tabular-nums;
  }

  .item,
  .trigger {
    cursor: pointer;
    gap: var(--moduix-pagination-trigger-gap, var(--moduix-spacing-2));
    border: var(--moduix-pagination-item-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-pagination-item-border-color, var(--moduix-color-border));
    padding-inline: var(--moduix-pagination-item-padding-inline, var(--moduix-spacing-3));
    background-color: var(--moduix-pagination-item-bg, var(--moduix-color-background));
    color: var(--moduix-pagination-item-color, var(--moduix-color-foreground));
    font-family: inherit;
    text-decoration: none;
    user-select: none;
    white-space: nowrap;
    transition:
      background-color var(--moduix-pagination-transition, var(--moduix-transition-default)),
      border-color var(--moduix-pagination-transition, var(--moduix-transition-default)),
      color var(--moduix-pagination-transition, var(--moduix-transition-default)),
      opacity var(--moduix-pagination-transition, var(--moduix-transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--moduix-pagination-item-bg-hover, var(--moduix-color-accent));
      }
    }

    &:focus-visible,
    &[data-focus] {
      outline: var(
          --moduix-pagination-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-pagination-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(
        --moduix-pagination-focus-ring-offset,
        var(--moduix-focus-ring-inset-offset)
      );
    }

    &:is([data-disabled], :disabled) {
      opacity: var(--moduix-pagination-disabled-opacity, var(--moduix-opacity-disabled));
      pointer-events: none;
    }

    & svg {
      flex-shrink: 0;
      width: var(--moduix-pagination-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-pagination-icon-size, var(--moduix-spacing-4));
    }
  }

  .item[data-selected] {
    border-color: var(
      --moduix-pagination-item-border-color-selected,
      var(--moduix-color-foreground)
    );
    background-color: var(--moduix-pagination-item-bg-selected, var(--moduix-color-foreground));
    color: var(--moduix-pagination-item-color-selected, var(--moduix-color-background));

    @media (hover: hover) {
      &:hover {
        background-color: var(--moduix-pagination-item-bg-selected, var(--moduix-color-foreground));
      }
    }
  }

  .trigger {
    padding-inline: max(
      var(--moduix-pagination-item-padding-inline, var(--moduix-spacing-3)),
      var(--moduix-spacing-3)
    );
  }

  .iconTrigger {
    width: var(--moduix-pagination-item-size, var(--moduix-size-md));
    padding-inline: 0;
  }

  .ellipsis {
    color: var(--moduix-pagination-ellipsis-color, var(--moduix-color-muted-foreground));
    user-select: none;
  }

  .edgeIcon {
    display: inline-flex;
    align-items: center;
    justify-content: center;

    & svg + svg {
      margin-inline-start: calc(var(--moduix-pagination-icon-size, var(--moduix-spacing-4)) * -0.5);
    }
  }
}
